# -*- coding: utf-8 -*-

from typing import Dict, Iterable, List, Literal, TypedDict, Union, cast
from openai import OpenAI
from openai.types.chat import ChatCompletionMessageParam
from app.config import settings



class SimpleMessage(TypedDict):
    role: Literal["system", "user", "assistant"]
    content: str

MessageInput = Union[ChatCompletionMessageParam, Dict[str, str]]

class QwenClient:
    def __init__(
        self,
        model: str = settings.MODEL_ID,
        base_url: str = settings.DASHSCOPE_BASE_URL,
        api_key: str = settings.DASHSCOPE_API_KEY,
    ) -> None:
        self.model = model
        self.client = OpenAI(
            api_key=api_key,
            base_url=base_url,
        )

    def _normalize_messages(self, messages: Iterable[MessageInput]) -> List[ChatCompletionMessageParam]:
        """messages类型转换，支持list[dict[str,str]]"""
        normalized: List[ChatCompletionMessageParam] = []

        for i, msg in enumerate(messages):
            if not isinstance(msg, dict):
                raise TypeError("messages[%d] must be dict" % i)

            role = msg.get("role")
            content = msg.get("content")

            if role not in ("system", "user", "assistant"):
                raise ValueError("messages[%d].role is invalid: %s" % (i, role))
            if not isinstance(content, str):
                raise TypeError("messages[%d].content must be str" % i)

            normalized.append(
                cast(ChatCompletionMessageParam, {"role": role, "content": content})
            )

        return normalized

    def chat(self, messages: Iterable[MessageInput]) -> str:
        normalized = self._normalize_messages(messages)
        resp = self.client.chat.completions.create(
            model=self.model,
            messages=normalized,
        )
        return resp.choices[0].message.content or ""


    def ask(self, prompt: str, system_prompt: str = "你是一个有帮助的助手") -> str:
        messages: Iterable[ChatCompletionMessageParam] = [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": prompt},
        ]
        return self.chat(messages)


if __name__ == "__main__":
    client = QwenClient()
    result = client.ask("请解释一下什么是 RAG")
    print(result)

